// Ensure "Execute Once" is toggled ON for this node
const articles = $input.all();
let formattedFeed = "Here are the latest technology and macro finance stories to analyze:\n\n";

// State trackers to enforce strict 5-item engineering quotas per source
let hnCount = 0;
let tcCount = 0;
let yahooCount = 0;
let displayCount = 1;

for (const item of articles) {
    const data = item.json;
    if (!data || !data.title) continue;

    let source = "Unknown";
    let link = data.link || data.guid || "";

    // Identify source origin dynamically by inspecting the destination URL
    if (link.includes("ycombinator.com") || (data.description && data.description.includes("ycombinator.com"))) {
        source = "Hacker News";
        if (hnCount >= 5) continue; // Drop item if we already have 5 HN articles
        hnCount++;
    } else if (link.includes("techcrunch.com")) {
        source = "TechCrunch";
        if (tcCount >= 5) continue; // Drop item if we already have 5 TechCrunch articles
        tcCount++;
    } else if (link.includes("yahoo.com")) {
        source = "Yahoo Finance";
        if (yahooCount >= 5) continue; // Drop item if we already have 5 Yahoo articles
        yahooCount++;
    }

    // Clean and normalize the headline string to prevent XML token bloating
    let cleanTitle = data.title.trim()
        .replace(/&amp;/g, '&')
        .replace(/&quot;/g, '"')
        .replace(/&#x27;/g, "'")
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>');

    // Build the consolidated text payload for the LLM
    formattedFeed += `${displayCount}. TITLE: ${cleanTitle}\n`;
    formattedFeed += `   SOURCE: ${source}\n`;
    formattedFeed += `   URL: ${link.trim()}\n\n`;

    displayCount++;
}

return [{ json: { cleanFeedText: formattedFeed } }];

// Ensure "Execute Once" is turned OFF on this node so it runs per array entry
const chunks = [];
const limit = 1800; // Rigid safety ceiling under Discord's 2000 character wall

// 1. Safe extraction syntax matching standard LLM Chain output
const fullText = $json.text || "";

if (fullText.length <= limit) {
    if (fullText.trim()) {
        chunks.push({ json: { chunkText: fullText.trim() } });
    }
} else {
    // Split by newlines to keep paragraph formatting intact
    const paragraphs = fullText.split('\n');
    let currentChunk = "";

    for (const para of paragraphs) {
        // Handle edge case: what if a single paragraph is monstrously long?
        if (para.length > limit) {
            // If we have text stored up, flush it out first
            if (currentChunk.trim()) {
                chunks.push({ json: { chunkText: currentChunk.trim() } });
                currentChunk = "";
            }
            // Hard-slice the monstrous paragraph into valid sub-chunks
            let subPara = para;
            while (subPara.length > limit) {
                chunks.push({ json: { chunkText: subPara.substring(0, limit).trim() } });
                subPara = subPara.substring(limit);
            }
            currentChunk = subPara + "\n";
            continue;
        }

        // Standard boundary evaluation
        if ((currentChunk + para).length > limit) {
            if (currentChunk.trim()) {
                chunks.push({ json: { chunkText: currentChunk.trim() } });
            }
            currentChunk = para + "\n";
        } else {
            currentChunk += para + "\n";
        }
    }

    // Flush any remaining characters left over in the buffer
    if (currentChunk.trim()) {
        chunks.push({ json: { chunkText: currentChunk.trim() } });
    }
}

return chunks;
